def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for idx, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1.0:
            continue
        score = 0.0
        for n in range(1, 20):
            base_term = (1 / (n ** 3)) * (ratio ** n)
            if n % 4 == 0:
                base_term *= 1.3
            elif n % 6 == 0:
                base_term *= 0.85
            else:
                base_term *= 0.95 + 0.05 * ((-1) ** n)
            score += base_term
        remainder = capacity - item
        if remainder < 0.02 * capacity:
            score *= 3.0
        elif remainder < 0.07 * capacity:
            score *= 1.7
        elif remainder < 0.12 * capacity:
            score *= 1.25
        elif remainder < 0.25 * capacity:
            score *= 0.95
        else:
            score *= 0.7
        mod_conditions = [int(capacity) % p == 0 for p in [2, 3, 5, 7, 11]]
        if all(mod_conditions):
            score -= 0.2 * (capacity / 12)
        elif mod_conditions[0] and mod_conditions[2]:
            score -= 0.15 * (capacity / 18)
        elif mod_conditions[1] and mod_conditions[3]:
            score -= 0.12 * (capacity / 14)
        elif mod_conditions[4]:
            score -= 0.1 * (capacity / 20)
        else:
            score -= 0.04 * (capacity / 35)
        penalty = 0
        for k in range(1, 8):
            dist = abs(capacity - item * k)
            threshold1 = 0.012 * capacity * k
            threshold2 = 0.025 * capacity * k
            threshold3 = 0.05 * capacity * k
            if dist < threshold1:
                penalty += 0.3 * k
            elif dist < threshold2:
                penalty += 0.15 * k
            elif dist < threshold3:
                penalty -= 0.05 * k
            else:
                penalty -= 0.1 * k
        score += penalty
        special_boost = 0
        for m in range(1, 5):
            target = capacity / m
            if abs(item - target) < 0.015 * target:
                special_boost += 0.06 * m
            elif abs(item - target) < 0.04 * target:
                special_boost += 0.02 * m
            else:
                special_boost -= 0.01 * m
        score *= 1 + special_boost
        if score < 0:
            score = 0
        if ratio > 0.85 and remainder > 0.01 * capacity:
            extra = 0
            for p in range(1, 10):
                factor = (-1) ** p * (ratio ** p) / (p + 1)
                extra += factor
            score += extra * 0.5
        priorities[idx] = score
    return priorities
